import { ApiProperty } from '@nestjs/swagger';
import { Equals, IsOptional, IsString } from 'class-validator';

export class LocalShellCallOutputDto {
  /** The unique ID of the local shell tool call generated by the model. */
  @ApiProperty({ description: `The unique ID of the local shell tool call generated by the model.`, type: 'string' })
  @IsString()
  id!: string;

  /** A JSON string of the output of the local shell tool call. */
  @ApiProperty({ description: `A JSON string of the output of the local shell tool call.`, type: 'string' })
  @IsString()
  output!: string;

  /** The type of the local shell tool call output. Always `local_shell_call_output`. */
  @ApiProperty({ description: `The type of the local shell tool call output. Always \`local_shell_call_output\`.`, example: 'local_shell_call_output' })
  @Equals('local_shell_call_output')
  type!: 'local_shell_call_output';

  /** The status of the item. One of `in_progress`, `completed`, or `incomplete`. */
  @ApiProperty({ required: false, description: `The status of the item. One of \`in_progress\`, \`completed\`, or \`incomplete\`.` })
  @IsOptional()
  status?: null | 'in_progress' | 'completed' | 'incomplete';
}
